                print(f"Failed to grade {image_path} after {max_retries} attempts.")
                # Return a fallback empty result to not crash everything
                return {"answers": ["A"] * 30, "subjective_score": 0}

def process_student(filename):
    filepath = os.path.join("context/pictures", filename)
    student_id = filename.split('.')[0]

    print(f"Processing student {student_id}...")
    result_dict = grade_image(filepath)

    # Calculate objective score
    answers = result_dict.get('answers', [])
    # Make sure we only compare up to the minimum length to avoid index errors
    compare_len = min(len(answers), len(CORRECT_ANSWERS))
    correct_count = sum(1 for i in range(compare_len) if str(answers[i]).upper() == CORRECT_ANSWERS[i])

    objective_score = correct_count * 3

    # Get subjective score
    try:
        subjective_score = int(result_dict.get('subjective_score', 0))
    except (ValueError, TypeError):
        subjective_score = 0

    total_score = objective_score + subjective_score

    return {
        "student_id": str(student_id),  # Ensure it's a string as in example
        "objective_score": objective_score,
        "subjective_score": subjective_score,
        "total_score": total_score
    }

def main():
    pictures_dir = "context/pictures"
    filenames = [f for f in os.listdir(pictures_dir) if f.endswith(('.png', '.jpg', '.jpeg'))]

    # Sort logically so 1, 2, 10 order correctly
    filenames.sort(key=lambda x: int(x.split('.')[0]))

    results = []

    # Use ThreadPoolExecutor for concurrent API calls to speed up
    with concurrent.futures.ThreadPoolExecutor(max_workers=5) as executor:
        future_to_file = {executor.submit(process_student, filename): filename for filename in filenames}

        for future in concurrent.futures.as_completed(future_to_file):
            filename = future_to_file[future]
            try:
                data = future.result()
                results.append(data)
                print(f"Completed {data['student_id']}: Obj {data['objective_score']}, Subj {data['subjective_score']}, Total {data['total_score']}")
            except Exception as exc:
                print(f"{filename} generated an exception: {exc}")

    # Sort results by student ID before saving
    results.sort(key=lambda x: int(x['student_id']))

    with open("grading_results.json", "w", encoding="utf-8") as f:
        json.dump(results, f, ensure_ascii=False, indent=2)

    print(f"Saved {len(results)} results to grading_results.json")

if __name__ == "__main__":
    main()
